solution_code:
#include <stdio.h>
#include <stdlib.h>

int *buffer_resize(int *buf, size_t old_size, size_t new_size) {
    (void)old_size;
    int *tmp = realloc(buf, new_size * sizeof(int));
    if (!tmp) { free(buf); return NULL; }
    return tmp;
}

validation.test_code:
int *buffer_resize(int *buf, size_t old_size, size_t new_size);

void test_resize_grow(void) {
    int *buf = malloc(2 * sizeof(int));
    TEST_ASSERT_NOT_NULL(buf);
    buf[0] = 10; buf[1] = 20;
    int *tmp = buffer_resize(buf, 2, 4);
    TEST_ASSERT_NOT_NULL(tmp);
    TEST_ASSERT_EQUAL_INT(10, tmp[0]);
    TEST_ASSERT_EQUAL_INT(20, tmp[1]);
    free(tmp);
}

void test_resize_preserves_data(void) {
    int *buf = malloc(3 * sizeof(int));
    buf[0] = 5; buf[1] = 10; buf[2] = 15;
    int *tmp = buffer_resize(buf, 3, 6);
    TEST_ASSERT_EQUAL_INT(5, tmp[0]);
    TEST_ASSERT_EQUAL_INT(10, tmp[1]);
    TEST_ASSERT_EQUAL_INT(15, tmp[2]);
    free(tmp);
}

void test_resize_allows_new_data(void) {
    int *buf = malloc(1 * sizeof(int));
    buf[0] = 1;
    int *tmp = buffer_resize(buf, 1, 3);
    TEST_ASSERT_NOT_NULL(tmp);
    tmp[1] = 2; tmp[2] = 3;
    TEST_ASSERT_EQUAL_INT(1, tmp[0]);
    TEST_ASSERT_EQUAL_INT(2, tmp[1]);
    TEST_ASSERT_EQUAL_INT(3, tmp[2]);
    free(tmp);
}

int main(void) {
    RUN_TEST(test_resize_grow);
    RUN_TEST(test_resize_preserves_data);
    RUN_TEST(test_resize_allows_new_data);
    TEST_SUMMARY();
    return _clings_failures > 0 ? 1 : 0;
}

