 * Reduire un buffer avec realloc (shrink)
 * realloc(ptr, new_size) peut agrandir OU reduire un bloc.
 * =========================================================== */
void example_shrink(void) {
    int *buf = malloc(4 * sizeof(int));
    if (!buf) return;
    buf[0] = 1; buf[1] = 2; buf[2] = 3; buf[3] = 4;
    printf("Avant shrink: %d %d %d %d\n", buf[0], buf[1], buf[2], buf[3]);
    int *tmp = realloc(buf, 2 * sizeof(int));
    if (!tmp) { free(buf); return; }
    buf = tmp;
    printf("Apres shrink: %d %d\n", buf[0], buf[1]);
    free(buf);
}
